import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Household Measurement","description":"","frontmatter":{"title":"Household Measurement","slug":"changelog-household-measurement"},"headers":[],"relativePath":"account-hub/changelog-household-measurement.md","filePath":"account-hub/changelog-household-measurement.md"}'),i={name:"account-hub/changelog-household-measurement.md"};function n(s,e,l,u,h,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>With this powerful new attribution feature, you can finally track downstream conversions across multiple household devices.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>.png)</p><p>Household Measurement offers comprehensive attribution support for household devices, including CTVs, gaming consoles, mobile phones, laptops, and <a href="./household-measurement.html#what-is-household-measurement">others</a>.</p><p>With this feature, you can measure down-funnel events and get a holistic view of your users&#39; actions. This gives you the data you need to optimize your campaigns and your TV ad budgets.</p><h2 id="attribution-flows" tabindex="-1">Attribution Flows <a class="header-anchor" href="#attribution-flows" aria-label="Permalink to &quot;Attribution Flows&quot;">​</a></h2><p>Household Measurement supports three attribution flows:</p><ul><li>TV to TV</li><li>TV to Web/Mobile</li><li>Web/Mobile to TV</li></ul><p>Learn more about each in detail <a href="./household-measurement.html#attribution-flows">here</a>.</p><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><p>Enabling Household Measurement requires developer support.</p><p>Your team will need to decide on either a <strong>SDK</strong> or <strong>server-to-server</strong> integration, depending on your needs.</p><p>Use our <a href="./household-measurement.html#integration-guide">integration instructions</a> to help make your decision and begin an integration.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Household Measurement is part of our Performance Pro package, which also includes:</p><ul><li><a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement</a></li><li><a href="./roi-hub.html">ROI Hub</a></li><li><a href="./engagement-builder.html">Engagement Builder</a></li><li>And everything in <a href="./packaging.html#performance-essentials-tier">Performance Essentials</a>!</li></ul><p>Learn more on our Pricing <a href="./packaging.html#performance-pro-tier">page</a>.</p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><p>If you&#39;re ready to begin optimizing attribution coverage for your cross-device campaigns, contact our <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">sales team</a> to get started!</p>',19)])])}const p=a(i,[["render",n]]);export{m as __pageData,p as default};
